/**
 * Array Utilities
 * Safe array operations for onboarding components
 */
/**
 * Ensures the value is a valid array, returns empty array if not
 */
export declare const ensureArray: <T>(value: T[] | undefined | null) => T[];
/**
 * Safe includes check that handles undefined/null values
 */
export declare const safeIncludes: <T>(array: T[] | undefined | null, item: T) => boolean;
/**
 * Safe filter that handles undefined/null values
 */
export declare const safeFilter: <T>(array: T[] | undefined | null, predicate: (item: T) => boolean) => T[];
